/**
 * LoadingSkeleton — Reusable skeleton/shimmer loading component for Aura Alpha.
 *
 * Provides a unified API that wraps the existing SkeletonKit components
 * while adding a simpler variant-based interface.
 *
 * Props:
 *   variant   - 'text' | 'card' | 'table' | 'chart' (default: 'text')
 *   width     - CSS width (default: '100%')
 *   height    - CSS height (default: auto based on variant)
 *   rows      - Number of rows for text/table variant (default: 3/5)
 *   cols      - Number of columns for table variant (default: 4)
 *   count     - Number of items for card variant (default: 1)
 *   style     - Additional inline styles on the container
 */

import React from 'react'

const colors = {
  surface: '#0F1620',
  border: '#1F2A37',
  shimmerBase: '#111A24',
  shimmerHighlight: '#1A2A3D',
  shimmerAccent: '#1B2D42',
};

const shimmerKeyframes = `
@keyframes loadingSkeletonShimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}
`;

const baseShimmer: React.CSSProperties = {
  animationName: 'loadingSkeletonShimmer',
  animationDuration: '1.8s',
  animationTimingFunction: 'linear',
  animationIterationCount: 'infinite',
  backgroundImage: `linear-gradient(90deg, ${colors.shimmerBase} 0%, ${colors.shimmerHighlight} 40%, ${colors.shimmerAccent} 50%, ${colors.shimmerHighlight} 60%, ${colors.shimmerBase} 100%)`,
  backgroundSize: '200% 100%',
  backgroundRepeat: 'no-repeat',
};

interface ShimmerBarProps {
  width?: string | number
  height?: number
  delay?: number
  borderRadius?: number
  style?: React.CSSProperties
}

function ShimmerBar({ width = '100%', height = 14, delay = 0, borderRadius = 4, style = {} }: ShimmerBarProps) {
  return (
    <div
      style={{
        width,
        height,
        borderRadius,
        ...baseShimmer,
        animationDelay: `${delay}s`,
        ...style,
      }}
    />
  );
}

/* ── Text skeleton ────────────────────────────────────────────────────────── */
interface TextSkeletonProps {
  rows?: number
  width?: string | number
}

function TextSkeleton({ rows = 3, width }: TextSkeletonProps) {
  const containerWidth = width || '100%';
  return (
    <div
      aria-busy="true"
      aria-label="Loading text"
      style={{
        width: containerWidth,
        display: 'flex',
        flexDirection: 'column',
        gap: 10,
      }}
    >
      {Array.from({ length: rows }).map((_, i) => {
        const lineWidth = i === rows - 1 ? `${55 + Math.floor(Math.random() * 30)}%` : '100%';
        return (
          <ShimmerBar
            key={i}
            width={lineWidth}
            height={14}
            delay={i * 0.08}
            borderRadius={6}
          />
        );
      })}
    </div>
  );
}

/* ── Card skeleton ────────────────────────────────────────────────────────── */
interface CardSkeletonProps {
  count?: number
  width?: string | number
  height?: number
}

function CardSkeleton({ count = 1, width, height = 160 }: CardSkeletonProps) {
  const cards = Array.from({ length: count }).map((_, i) => (
    <div
      key={i}
      aria-busy="true"
      aria-label="Loading card"
      style={{
        width: count > 1 ? '100%' : (width || '100%'),
        minHeight: height,
        borderRadius: 14,
        backgroundColor: colors.surface,
        border: `1px solid ${colors.border}`,
        padding: 16,
        display: 'flex',
        flexDirection: 'column',
        gap: 12,
        boxSizing: 'border-box',
      }}
    >
      {/* Header area */}
      <ShimmerBar width="100%" height={height * 0.3} borderRadius={8} delay={i * 0.1} />
      {/* Text lines */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        <ShimmerBar width="85%" height={12} delay={0.1 + i * 0.08} />
        <ShimmerBar width="65%" height={12} delay={0.18 + i * 0.08} />
      </div>
      {/* Metric row */}
      <div style={{ display: 'flex', gap: 12, marginTop: 'auto' }}>
        <ShimmerBar width="25%" height={10} delay={0.25 + i * 0.08} />
        <ShimmerBar width="20%" height={10} delay={0.3 + i * 0.08} />
        <ShimmerBar width="22%" height={10} delay={0.35 + i * 0.08} />
      </div>
    </div>
  ));

  if (count <= 1) return cards[0];

  return (
    <div style={{
      display: 'grid',
      gridTemplateColumns: `repeat(auto-fill, minmax(280px, 1fr))`,
      gap: 16,
    }}>
      {cards}
    </div>
  );
}

/* ── Table skeleton ───────────────────────────────────────────────────────── */
interface TableSkeletonProps {
  rows?: number
  cols?: number
  width?: string | number
}

function TableSkeleton({ rows = 5, cols = 4, width }: TableSkeletonProps) {
  const cellWidths = ['60%', '80%', '50%', '70%', '45%', '55%', '65%', '40%', '75%', '35%'];
  return (
    <div
      aria-busy="true"
      aria-label="Loading table data"
      style={{
        width: width || '100%',
        backgroundColor: colors.surface,
        border: `1px solid ${colors.border}`,
        borderRadius: 10,
        overflow: 'hidden',
      }}
    >
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr>
            {Array.from({ length: cols }).map((_, i) => (
              <th
                key={i}
                style={{
                  padding: '10px 12px',
                  borderBottom: `1px solid ${colors.border}`,
                  backgroundColor: colors.surface,
                }}
              >
                <ShimmerBar width="70%" height={10} delay={i * 0.06} />
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {Array.from({ length: rows }).map((_, r) => (
            <tr key={r}>
              {Array.from({ length: cols }).map((_, c) => (
                <td
                  key={c}
                  style={{
                    padding: '10px 12px',
                    borderBottom: r < rows - 1 ? `1px solid ${colors.border}` : 'none',
                  }}
                >
                  <ShimmerBar
                    width={cellWidths[(r + c) % cellWidths.length]}
                    height={14}
                    delay={(r * cols + c) * 0.04}
                  />
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ── Chart skeleton ───────────────────────────────────────────────────────── */
interface ChartSkeletonProps {
  height?: number
  width?: string | number
}

function ChartSkeleton({ height = 260, width }: ChartSkeletonProps) {
  return (
    <div
      aria-busy="true"
      aria-label="Loading chart"
      style={{
        width: width || '100%',
        height,
        borderRadius: 10,
        backgroundColor: colors.surface,
        border: `1px solid ${colors.border}`,
        position: 'relative',
        overflow: 'hidden',
      }}
    >
      {/* Y-axis labels */}
      <div style={{ position: 'absolute', left: 12, top: 20, display: 'flex', flexDirection: 'column', gap: 32 }}>
        {Array.from({ length: 4 }).map((_, i) => (
          <ShimmerBar key={i} width={32} height={10} delay={i * 0.1} />
        ))}
      </div>

      {/* Grid lines */}
      {Array.from({ length: 4 }).map((_, i) => (
        <div
          key={`grid-${i}`}
          style={{
            position: 'absolute',
            left: 56,
            right: 16,
            top: 24 + i * 48,
            height: 1,
            background: `${colors.border}50`,
          }}
        />
      ))}

      {/* Chart area */}
      <div
        style={{
          position: 'absolute',
          left: 56,
          right: 16,
          top: 20,
          bottom: 36,
          borderRadius: 6,
          ...baseShimmer,
          animationDelay: '0.15s',
          opacity: 0.6,
        }}
      />

      {/* X-axis labels */}
      <div style={{
        position: 'absolute',
        bottom: 10,
        left: 56,
        right: 16,
        display: 'flex',
        justifyContent: 'space-between',
      }}>
        {Array.from({ length: 6 }).map((_, i) => (
          <ShimmerBar key={i} width={32} height={8} delay={0.1 * i} />
        ))}
      </div>
    </div>
  );
}

/* ── Main component ───────────────────────────────────────────────────────── */
export type LoadingSkeletonVariant = 'text' | 'card' | 'table' | 'chart'

export interface LoadingSkeletonProps {
  variant?: LoadingSkeletonVariant
  width?: string | number
  height?: number
  rows?: number
  cols?: number
  count?: number
  style?: React.CSSProperties
}

export default function LoadingSkeleton({
  variant = 'text',
  width,
  height,
  rows,
  cols,
  count,
  style,
}: LoadingSkeletonProps) {
  return (
    <div style={style}>
      <style>{shimmerKeyframes}</style>
      {variant === 'text' && (
        <TextSkeleton rows={rows || 3} width={width} />
      )}
      {variant === 'card' && (
        <CardSkeleton count={count || 1} width={width} height={height || 160} />
      )}
      {variant === 'table' && (
        <TableSkeleton rows={rows || 5} cols={cols || 4} width={width} />
      )}
      {variant === 'chart' && (
        <ChartSkeleton height={height || 260} width={width} />
      )}
    </div>
  );
}

/* Named exports for direct access */
export { TextSkeleton, CardSkeleton, TableSkeleton, ChartSkeleton, ShimmerBar };
