/**
 * SkipToContent — Accessibility shortcut for keyboard navigation.
 *
 * Renders a visually hidden link that becomes visible on focus,
 * allowing keyboard users to skip past navigation to the main content.
 *
 * Props:
 *   href    - Target anchor (default: '#main-content')
 *   label   - Link text (default: 'Skip to main content')
 */
export default function SkipToContent({
  href = '#main-content',
  label = 'Skip to main content',
}) {
  return (
    <a
      href={href}
      className="sr-only focus:not-sr-only focus:absolute focus:top-2 focus:left-2 focus:z-50 focus:bg-blue-600 focus:text-white focus:px-4 focus:py-2 focus:rounded focus:outline-none focus:ring-2 focus:ring-blue-400"
      style={{
        fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
        fontSize: 13,
        fontWeight: 600,
      }}
    >
      {label}
    </a>
  );
}
