function PropsTable({ rows }) {
  return (
    <div style={{ overflowX: 'auto' }}>
      <table style={propsTableStyle}>
        <thead>
          <tr>
            <th style={thStyle}>Prop</th>
            <th style={thStyle}>Type</th>
            <th style={thStyle}>Default</th>
            <th style={thStyle}>Description</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td style={codeTdStyle}>{r[0]}</td>
              <td style={codeTdStyle}>{r[1]}</td>
              <td style={{ ...tdStyle, fontFamily: mono, fontSize: 11 }}>{r[2]}</td>
              <td style={tdStyle}>{r[3]}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ── Intentional error trigger for ErrorBoundary demo ─────────────────── */
function BuggyComponent() {
  throw new Error('Demo crash: this error is intentional!');
}

function ErrorBoundaryDemo() {
  const [showCrash, setShowCrash] = useState(false);
  return (
    <div>
      <button
        onClick={() => setShowCrash(true)}
        style={{
          padding: '8px 16px',
          borderRadius: 8,
          background: 'rgba(248,81,73,0.15)',
          border: '1px solid rgba(248,81,73,0.3)',
          color: '#F85149',
          fontSize: 12,
          fontWeight: 600,
          cursor: 'pointer',
          fontFamily: font,
          marginBottom: 16,
        }}
      >
        Trigger Error
      </button>
      <SectionErrorBoundary name="Demo Component" onReset={() => setShowCrash(false)}>
        {showCrash ? <BuggyComponent /> : (
          <GlassPanel>
            <span style={{ fontFamily: font, fontSize: 13, color: tokens.color.text }}>
              This content is wrapped in a SectionErrorBoundary. Click the button above to crash it.
            </span>
          </GlassPanel>
        )}
      </SectionErrorBoundary>
    </div>
  );
}

/* ── Toast demo (needs to be inside ToastProvider) ─────────────────────── */
function ToastDemo() {
  const toast = useToast();
  return (
    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
      <DemoButton label="Success" onClick={() => toast.success('Saved', 'Your changes have been saved.')} color={tokens.color.green} />
      <DemoButton label="Error" onClick={() => toast.error('Failed', 'Could not connect to server.')} color={tokens.color.red} />
      <DemoButton label="Info" onClick={() => toast.info('Tip', 'Try the new strategy lab.')} color={tokens.color.blue} />
      <DemoButton label="Warning" onClick={() => toast.warning('Caution', 'Rate limit approaching.')} color={tokens.color.amber} />
    </div>
  );
}

function DemoButton({ label, onClick, color }) {
  return (
    <button
      onClick={onClick}
      style={{
        padding: '8px 16px',
        borderRadius: 8,
        background: `${color}20`,
        border: `1px solid ${color}40`,
        color,
        fontSize: 12,
        fontWeight: 600,
        cursor: 'pointer',
        fontFamily: font,
      }}
    >
      {label}
    </button>
  );
}

