import { Tab3D } from './Tab3D'
import './TabGroup.css'

export const TabGroup = ({
  tabs,
  activeTab,
  onTabChange,
  variant = 'default',
}) => {
  return (
    <div className={`tab-group tab-group-${variant}`} role="tablist">
      {tabs.map((tab) => (
        <Tab3D
          key={tab.id}
          label={tab.label}
          icon={tab.icon}
          badge={tab.badge}
          isActive={activeTab === tab.id}
          onClick={() => onTabChange(tab.id)}
        />
      ))}
    </div>
  )
}
