import './Tab3D.css'

export const Tab3D = ({
  label,
  isActive = false,
  onClick,
  icon,
  badge,
}) => {
  return (
    <button
      className={`tab-3d ${isActive ? 'active' : ''}`}
      onClick={onClick}
      aria-pressed={isActive}
    >
      {icon && <span className="tab-icon">{icon}</span>}
      <span className="tab-label">{label}</span>
      {badge && <span className="tab-badge">{badge}</span>}
    </button>
  )
}
