import { Suspense } from 'react';
import SectionErrorBoundary from './ErrorBoundary';
import LoadingSkeleton from './LoadingSkeleton';

/**
 * PageWrapper — Wraps a page with ErrorBoundary + Suspense.
 *
 * Provides consistent error recovery and loading states for any page.
 * Drop-in wrapper: just wrap your page content with <PageWrapper>.
 *
 * Props:
 *   name            - Page name shown in error fallback (e.g. "Dashboard")
 *   loadingVariant  - Skeleton variant during Suspense: 'text'|'card'|'table'|'chart'
 *   loadingRows     - Rows for text/table skeleton (default: 5)
 *   loadingCols     - Cols for table skeleton (default: 4)
 *   loadingHeight   - Height for chart skeleton (default: 300)
 *   fallback        - Custom Suspense fallback (overrides skeleton)
 *   errorFallback   - Custom error fallback (overrides ErrorBoundary default)
 *   onErrorReset    - Callback when user clicks "Try Again"
 *   noPadding       - Skip the default page padding (for pages with their own)
 *   children        - Page content
 */
export default function PageWrapper({
  name,
  loadingVariant = 'text',
  loadingRows,
  loadingCols,
  loadingHeight,
  fallback,
  errorFallback,
  onErrorReset,
  noPadding = false,
  children,
}) {
  const suspenseFallback = fallback || (
    <div style={{
      padding: noPadding ? 0 : '20px 24px',
      minHeight: 300,
      backgroundColor: '#0B0F14',
    }}>
      <LoadingSkeleton
        variant={loadingVariant}
        rows={loadingRows}
        cols={loadingCols}
        height={loadingHeight}
      />
    </div>
  );

  return (
    <SectionErrorBoundary
      name={name}
      fallback={errorFallback}
      onReset={onErrorReset}
    >
      <Suspense fallback={suspenseFallback}>
        {children}
      </Suspense>
    </SectionErrorBoundary>
  );
}
